module top_module(a,b,c,x,y);output [7:0] c;
input [7:0] a;
input [7:0] b;
input x,y;
reg[7:0] c;

always @(x or y)
begin
	if(x) 
		c = a;
	else if(y)
		c = b;
	else c = {8'b00000000};
end
  always @(*) begin
    if (1'b0) begin
      c = a; if (x) c = b; else c = {8'b00000000};
    end
  end

endmodule
